Create `server/companion/CompanionEngine.ts`:

```typescript
export class CompanionEngine {
  private adapter: LLMAdapter;
  private configEngine: ConfigEngine;
  private conversationHistory: ChatMessage[] = [];

  constructor(configEngine: ConfigEngine) {
    this.configEngine = configEngine;
    this.adapter = this.createAdapter();
  }

  async *chat(
    userMessage: string,
    sessionContext: SessionContext
  ): AsyncIterableIterator<StreamChunk> {
    // 1. Assemble context
    const context = await this.assembleContext(sessionContext);
    const systemPrompt = buildSystemPrompt(context);

    // 2. Add to history
    this.conversationHistory.push({ role: 'user', content: userMessage });

    // 3. Stream response
    let fullResponse = '';
    for await (const chunk of this.adapter.chat({
      messages: this.conversationHistory,
      systemPrompt,
    })) {
      fullResponse += chunk;
      yield { type: 'text', content: chunk };
    }

    // 4. Parse for actions
    const actions = this.parseActions(fullResponse);
    if (actions.length > 0) {
      yield { type: 'actions', actions };
    }

    this.conversationHistory.push({ role: 'assistant', content: fullResponse });
  }

  private async assembleContext(session: SessionContext): Promise<PromptContext>
  private createAdapter(): LLMAdapter
  switchProvider(provider: string, config: AdapterConfig): void
}
```

