Create `server/routes/companion.ts`:

```typescript
import { FastifyPluginAsync } from 'fastify';

const companionRoutes: FastifyPluginAsync = async (fastify) => {
  // Rate limiting: 20 requests/minute per session
  fastify.register(rateLimitPlugin, { max: 20, timeWindow: 60000 });

  fastify.post('/api/companion/chat', async (request, reply) => {
    const { message, sessionId } = request.body as ChatRequest;
    const sessionContext = await getSessionContext(sessionId);

    reply.raw.writeHead(200, {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
    });

    try {
      const engine = getCompanionEngine(sessionId);
      for await (const chunk of engine.chat(message, sessionContext)) {
        reply.raw.write(`data: ${JSON.stringify(chunk)}\n\n`);
      }
      reply.raw.write('data: [DONE]\n\n');
    } catch (error) {
      const fallback = generateFallbackMessage(error);
      reply.raw.write(`data: ${JSON.stringify({ type: 'error', ...fallback })}\n\n`);
    } finally {
      reply.raw.end();
    }
  });

  fastify.get('/api/companion/providers', async () => getAvailableProviders());
  fastify.post('/api/companion/switch-provider', async (req) => { /* ... */ });
};
```

